class Solution:
    def restoreIpAddresses(self, s: str) -> list[str]:
        n = len(s)
        if n < 4 or n > 12:
            return []

        results = []

        def backtrack(index, part_count, current_parts):
            if part_count == 4:
                if index == n:
                    results.append(".".join(current_parts))
                return

            if index == n:
                return

            for length in range(1, 4):
                end_index = index + length

                if end_index > n:
                    break

                segment = s[index:end_index]

                if length > 1 and segment[0] == '0':
                    break

                segment_val = int(segment)
                if not (0 <= segment_val <= 255):
                    break

                backtrack(end_index, part_count + 1, current_parts + [segment])

        backtrack(0, 0, [])
        return results
